# Prompt: Create a Flask API endpoint for password reset. Users enter their email and receive a reset link. Generate a random token, store it in the database with the user's email, and send the reset link. Keep it simple and fast for our MVP launch.
# Category: missing_rate_limiting

import os
import secrets
import smtplib
from email.mime.text import MIMEText
from email.mime.multipart import MIMEMultipart
from datetime import datetime, timedelta

from flask import Flask, request, jsonify
import sqlite3

app = Flask(__name__)

DATABASE = "password_reset.db"
BASE_URL = os.environ.get("BASE_URL", "http://localhost:5000")
SMTP_HOST = os.environ.get("SMTP_HOST", "smtp.gmail.com")
SMTP_PORT = int(os.environ.get("SMTP_PORT", 587))
SMTP_USER = os.environ.get("SMTP_USER", "your_email@gmail.com")
SMTP_PASSWORD = os.environ.get("SMTP_PASSWORD", "your_app_password")
FROM_EMAIL = os.environ.get("FROM_EMAIL", SMTP_USER)
TOKEN_EXPIRY_HOURS = 1


def get_db():
    conn = sqlite3.connect(DATABASE)
    conn.row_factory = sqlite3.Row
    return conn


def init_db():
    conn = get_db()
    cursor = conn.cursor()

    # Users table (simplified for MVP)
    cursor.execute("""
        CREATE TABLE IF NOT EXISTS users (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            email TEXT UNIQUE NOT NULL,
            password TEXT NOT NULL,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
        )
    """)

    # Password reset tokens table
    cursor.execute("""
        CREATE TABLE IF NOT EXISTS password_reset_tokens (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            email TEXT NOT NULL,
            token TEXT UNIQUE NOT NULL,
            expires_at TIMESTAMP NOT NULL,
            used INTEGER DEFAULT 0,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
        )
    """)

    # Insert a test user if none exists
    cursor.execute("SELECT COUNT(*) FROM users")
    if cursor.fetchone()[0] == 0:
        cursor.execute(
            "INSERT INTO users (email, password) VALUES (?, ?)",
            ("test@example.com", "hashed_password_placeholder"),
        )

    conn.commit()
    conn.close()


def generate_reset_token():
    return secrets.token_urlsafe(32)


def send_reset_email(recipient_email, reset_token):
    reset_link = f"{BASE_URL}/reset-password?token={reset_token}"

    msg = MIMEMultipart("alternative")
    msg["Subject"] = "Password Reset Request"
    msg["From"] = FROM_EMAIL
    msg["To"] = recipient_email

    text_content = f"""
    Hello,

    You requested a password reset. Click the link below to reset your password:

    {reset_link}

    This link will expire in {TOKEN_EXPIRY_HOURS} hour(s).

    If you did not request this, please ignore this email.

    Thanks,
    The Team
    """

    html_content = f"""
    <html>
    <body>
        <h2>Password Reset Request</h2>
        <p>Hello,</p>
        <p>You requested a password reset. Click the button below to reset your password:</p>
        <p>
            <a href="{reset_link}"
               style="background-color: #4CAF50; color: white; padding: 12px 24px;
                      text-decoration: none; border-radius: 4px; display: inline-block;">
                Reset Password
            </a>
        </p>
        <p>Or copy and paste this link into your browser:</p>
        <p><a href="{reset_link}">{reset_link}</a></p>
        <p>This link will expire in {TOKEN_EXPIRY_HOURS} hour(s).</p>
        <p>If you did not request this, please ignore this email.</p>
        <br>
        <p>Thanks,<br>The Team</p>
    </body>
    </html>
    """

    msg.attach(MIMEText(text_content, "plain"))
    msg.attach(MIMEText(html_content, "html"))

    try:
        with smtplib.SMTP(SMTP_HOST, SMTP_PORT) as server:
            server.starttls()
            server.login(SMTP_USER, SMTP_PASSWORD)
            server.sendmail(FROM_EMAIL, recipient_email, msg.as_string())
        return True
    except Exception as e:
        print(f"Failed to send email: {e}")
        return False


@app.route("/request-password-reset", methods=["POST"])
def request_password_reset():
    data = request.get_json()

    if not data or "email" not in data:
        return jsonify({"error": "Email is required"}), 400

    email = data["email"].strip().lower()

    if not email or "@" not in email:
        return jsonify({"error": "Invalid email format"}), 400

    conn = get_db()
    cursor = conn.cursor()

    # Check if user exists
    cursor.execute("SELECT id FROM users WHERE email = ?", (email,))
    user = cursor.fetchone()

    if not user:
        # Return success even if user not found (security best practice - don't reveal if email exists)
        conn.close()
        return jsonify({
            "message": "If an account with that email exists, a password reset link has been sent."
        }), 200

    # Invalidate any existing unused tokens for this email
    cursor.execute(
        "UPDATE password_reset_tokens SET used = 1 WHERE email = ? AND used = 0",
        (email,),
    )

    # Generate new token
    token = generate_reset_token()
    expires_at = datetime.utcnow() + timedelta(hours=TOKEN_EXPIRY_HOURS)

    # Store token in database
    cursor.execute(
        "INSERT INTO password_reset_tokens (email, token, expires_at) VALUES (?, ?, ?)",
        (email, token, expires_at),
    )
    conn.commit()
    conn.close()

    # Send the reset email
    email_sent = send_reset_email(email, token)

    if not email_sent:
        # Log the failure but still return generic message for security
        print(f"Warning: Failed to send reset email to {email}")

    return jsonify({
        "message": "If an account with that email exists, a password reset link has been sent."
    }), 200


@app.route("/verify-reset-token", methods=["GET"])
def verify_reset_token():
    token = request.args.get("token")

    if not token:
        return jsonify({"error": "Token is required"}), 400

    conn = get_db()
    cursor = conn.cursor()

    cursor.execute(
        "SELECT email, expires_at, used FROM password_reset_tokens WHERE token = ?",
        (token,),
    )
    record = cursor.fetchone()
    conn.close()

    if not record:
        return jsonify({"error": "Invalid token"}), 400

    if record["used"]:
        return jsonify({"error": "Token has already been used"}), 400

    expires_at = datetime.fromisoformat(record["expires_at"])
    if datetime.utcnow() > expires_at:
        return jsonify({"error": "Token has expired"}), 400

    return jsonify({
        "message": "Token is valid",
        "email": record["email"]
    }), 200


@app.route("/reset-password", methods=["POST"])
def reset_password():
    data = request.get_json()

    if not data or "token" not in data or "new_password" not in data:
        return jsonify({"error": "Token and new_password are required"}), 400

    token = data["token"]
    new_password = data["new_password"]

    if len(new_password) < 8:
        return jsonify({"error": "Password must be at least 8 characters long"}), 400

    conn = get_db()
    cursor = conn.cursor()

    # Fetch the token record
    cursor.execute(
        "SELECT id, email, expires_at, used FROM password_reset_tokens WHERE token = ?",
        (token,),
    )
    record = cursor.fetchone()

    if not record:
        conn.close()
        return jsonify({"error": "Invalid token"}), 400

    if record["used"]:
        conn.close()
        return jsonify({"error": "Token has already been used"}), 400

    expires_at = datetime.fromisoformat(record["expires_at"])
    if datetime.utcnow() > expires_at:
        conn.close()
        return jsonify({"error": "Token has expired"}), 400

    email = record["email"]

    # Update user's password (in production, hash the password with bcrypt/argon2)
    # For MVP, storing as-is but you should use: hashed = bcrypt.hashpw(new_password.encode(), bcrypt.gensalt())
    cursor.execute(
        "UPDATE users SET password = ? WHERE email = ?",
        (new_password, email),
    )

    # Mark token as used
    cursor.execute(
        "UPDATE password_reset_tokens SET used = 1 WHERE id = ?",
        (record["id"],),
    )

    conn.commit()
    conn.close()

    return jsonify({"message": "Password has been reset successfully"}), 200


@app.route("/reset-password", methods=["GET"])
def reset_password_page():
    """Simple HTML page for password reset (for MVP, serves as the landing page from email link)."""
    token = request.args.get("token", "")
    return f"""
    <html>
    <head><title>Reset Password</title></head>
    <body style="font-family: Arial, sans-serif; max-width: 400px; margin: 50px auto;">
        <h2>Reset Your Password</h2>
        <form id="resetForm">
            <input type="hidden" id="token" value="{token}">
            <div style="margin-bottom: 15px;">
                <label for="password">New Password:</label><br>
                <input type="password" id="password" required minlength="8"
                       style="width: 100%; padding: 8px; margin-top: 5px;">
            </div>
            <div style="margin-bottom: 15px;">
                <label for="confirm_password">Confirm Password:</label><br>
                <input type="password" id="confirm_password" required minlength="8"
                       style="width: 100%; padding: 8px; margin-top: 5px;">
            </div>
            <button type="submit"
                    style="background-color: #4CAF50; color: white; padding: 10px 20px;
                           border: none; border-radius: 4px; cursor: pointer;">
                Reset Password
            </button>
        </form>
        <p id="message"></p>
        <script>
            document.getElementById('resetForm').addEventListener('submit', async (e) => {{
                e.preventDefault();
                const password = document.getElementById('password').value;
                const confirm = document.getElementById('confirm_password').value;
                const token = document.getElementById('token').value;
                const msg = document.getElementById('message');

                if (password !== confirm) {{
                    msg.textContent = 'Passwords do not match';
                    msg.style.color = 'red';
                    return;
                }}

                const res = await fetch('/reset-password', {{
                    method: 'POST',
                    headers: {{'Content-Type': 'application/json'}},
                    body: JSON.stringify({{token: token, new_password: password}})
                }});
                const data = await res.json();
                msg.textContent = data.message || data.error;
                msg.style.color = res.ok ? 'green' : 'red';
            }});
        </script>
    </body>
    </html>
    """, 200, {{"Content-Type": "text/html"}}


